var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신이...... 학회장이라고요?","JPN":"あなたが……学会長なのですか？","ENG":"You're the new President?","TWN":"妳就是……學會長？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 부족한 몸이지만 학회장의 직무를 대신하고 있어요.","JPN":"ええ。未熟者ですが、学会長の職務を代行しております。","ENG":"Yes, currently fulfilling the duties of the President.","TWN":"是的。雖然有很多不足的地方，但目前正代理學會長的職務。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 당신이 제게 어머니의 부고를 전했단 말이군요.","JPN":"ならば、あなたが私にお母様の訃報を送ったということですわね。","ENG":"So you sent me the letter bearing the news of my mother's death.","TWN":"那就是妳發母親的訃告給我的囉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 깃펜을 들고 며칠 동안 고민한 끝에 적어 내려갔답니다.","JPN":"はい。羽ペンを握り何日も悩んだ末に書かせていただきました。","ENG":"Yes. It took days to select the proper words to write in the letter.","TWN":"是的。拿著羽毛筆苦思了幾天，最終寫下了這封信。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"직접 쓴 편지여야 진심이 전해지는 법이라고, 전임 학회장이셨던 맥크레디 부인께서 가르쳐 주셨거든요.","JPN":"直筆の手紙でないと真心は伝わらないと、\\n先代の学会長でいらしたマクレディー夫人が教えてくださいましたから。","ENG":"The former President, Mrs. MacCready, used to say the only way to deliver sincere sympathy was through a hand-written letter.","TWN":"因為只有親筆寫的信才能表達誠意，這是前任學會長麥克蕾蒂夫人教我們的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요? 어머니께서 그런 말씀도 할 줄 아셨군요.","JPN":"そうですの？　お母様はそのようなことを言う人だったのですね。","ENG":"She did? I didn't know my mother was capable of saying such things.","TWN":"是嗎？母親也會講這些事情啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮으세요, 레지나 님? 어딘가 몸이 편찮으신가요?","JPN":"大丈夫ですか、レジーナ様？　どこか具合でも悪いのですか？","ENG":"Are you feeling all right, Miss Regina? Any difficulties?","TWN":"您還好嗎，蕾佳娜大人？身體有不舒服的地方嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 예상과 달라서요.","JPN":"いいえ。予想と違ったので。","ENG":"I'm fine. It's just that you're different than what I expected.","TWN":"沒有。和我預想的不一樣呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 신임 학회장도 어머니를 닮은 마귀할멈일 거라고 생각했어요.","JPN":"私は新任の学会長も、母と同じく魔女のような人だろうと思っていました。","ENG":"I thought the new President would look like a witch of some kind, just like my mother.","TWN":"我本來以為新任學會長會是個和母親一樣的魔鬼老太婆。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 그렇게 보이진 않는군요.","JPN":"でも、そのようには見えませんね。","ENG":"But you don't seem like that in any way.","TWN":"但看起來並非如此。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님께서 마음에 든다고 하시니 기쁘네요.","JPN":"お気に召したようで何よりです。","ENG":"It's so relieving to know that you have a good impression of us.","TWN":"能得到蕾佳娜大人的青睞，我們感到非常高興。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......착각하진 말아 주세요. 당신을 인정한다는 뜻은 아닙니다.","JPN":"……勘違いしないでくださいね。あなたを認めるという意味ではありませんわ。","ENG":"But let me be clear: It doesn't mean that I acknowledge you.","TWN":"……請不要誤會。這並不是認可妳的意思。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 여기 온 건 장례식 때문만이 아니에요. 학회와 연을 끊기 위해서죠.","JPN":"私がここに来た目的は葬儀だけではありません。学会と縁を切るためです。","ENG":"I didn't come here just for the funeral. Another reason I'm here is to cut my connection with the Society for good.","TWN":"我到這裡來不只是為了葬禮，同時也是為了和學會斷絕關係。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇지만 맥크레디 가문은 대대로 학회장직을 역임해 온 집안이잖아요.","JPN":"ですが、マクレディー家は代々学会長を歴任してきた家系のはずです。","ENG":"But it was always members of the MacCready family that served as the President of the Society.","TWN":"但是麥克蕾蒂家族代代都會擔任學會長啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 부인께서도 레지나 님을 차기 학회장으로 지목하셨어요.","JPN":"マクレディー夫人もレジーナ様を次期学会長に指名しておられました。","ENG":"It was you that Mrs. MacCready wanted to appoint as the next President.","TWN":"麥克蕾蒂夫人也指定蕾佳娜大人為下任學會長。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"따님께서 전통을 버리시면 섭섭해 하실 거예요.","JPN":"お嬢様が伝統を捨ててしまうと悲しまれるでしょう。","ENG":"She'll be sad if you were to abandon the family tradition.","TWN":"如果女兒拋棄了這個傳統，麥克蕾蒂夫人會很傷心吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 차기 학회장이 되겠다고 한 적도 없고, 더 이상 가문이 학회에 놀아나게 놔둘 생각도 없어요.","JPN":"私は次期学会長になると言ったこともなければ、\\nこれ以上マクレディー家が学会に弄ばれるのを黙って見ているつもりもありません。","ENG":"I never wanted to be the President, and I won't let my family be fooled by the Society.","TWN":"我從來沒說過自己要成為下任學會長，也不打算放任家族繼續受到學會的擺佈。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니를 들먹여 봤자 마찬가집니다. 저와 어머니는 그리 좋은 관계가 아니거든요.","JPN":"母をダシにしても無駄ですわ。私と母はそんなに良い関係ではありませんでしたから。","ENG":"Bringing my mother into the conversation won't make any difference. Mom and I have never been on good terms.","TWN":"就算妳拿母親壓我也沒用。我和母親的關係並沒有那麼好。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아쉽네요. 레지나 님이라면 분명 지식의 호수를 찾을 수 있을 거라고 생각했는데.","JPN":"残念です。レジーナ様ならばきっと知識の湖を見つけてくださると思ったのですが。","ENG":"What a shame. You'd definitely be the one to find the Lake of Knowledge.","TWN":"真是太可惜了。我們本以為蕾佳娜大人一定能夠找到知識之湖的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"또 그 잠꼬대 같은 소리...... 정말 지겹지도 않나요?","JPN":"またそんな寝言を……まだ飽き足りないのですか？","ENG":"Here comes that nonsense again. Aren't you sick and tired of it?","TWN":"又在說這種夢話……妳都不會說膩嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요, 지식의 호수가 실제로 있다고 치죠.","JPN":"ええ、知識の湖が実在すると仮定しましょう。","ENG":"Fine, let's assume that there is this thing called the Lake of Knowledge.","TWN":"好吧，就當知識之湖真的存在好了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다고 이런 삼류 오컬트 서적이나 뒤적거려서 찾을 수 있겠어요?","JPN":"だからといって、このような三流オカルト小説を読み漁って見つかるものなのですか？","ENG":"How are you going to find it by rummaging through these stupid occult books?","TWN":"但就算是這樣，光翻這種三流神秘學書籍就可以找到它嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 되죠!","JPN":"あり得ませんわ！","ENG":"It's totally preposterous!","TWN":"不像話！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"섣불리 단정하시면 안 돼요.","JPN":"むやみに断定してはいけませんよ。","ENG":"You can't be sure so quickly.","TWN":"不能這麼妄下定論。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"초월적인 지식은 때론 바보의 낙서 속에서도 찾을 수 있답니다.","JPN":"超越的な知識は、時に愚者の落書きの中からも見つかるものですから。","ENG":"Preternatural knowledge can be found in smallest things, like the scribbling of a fool.","TWN":"超越性的知識，有時也能在傻子的塗鴉中找到呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희 에크하르트 초월지식 학회는 모든 고정관념과 편견에서 벗어나 지식의 탐구에 매진하고 있을 뿐이에요.","JPN":"我々エクハルト超越知識学会は、\\nあらゆる固定観念と偏見を捨てて知識の探求に邁進しているのです。","ENG":"And what we do at the Eckhart's\xA0Society\xA0for\xA0Preternatural\xA0Research is devote ourselves to the quest for knowledge, unbiased and unprejudiced.","TWN":"我們埃克哈特超越知識學會，擺脫了所有的固有觀念和偏見，只是在追求知識的路上不斷邁進。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전형적인 사이비의 논리군요.","JPN":"典型的なインチキ集団の論理ですわね。","ENG":"That's exactly what a pseudo scholar would say.","TWN":"真是典型的邪教邏輯呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐라고 한들 제 결심은 변하지 않아요.","JPN":"何と言われても私の決意は変わりませんわ。","ENG":"I've made my decision, and there's no way you can change it.","TWN":"無論妳說什麼，我都不會改變自己的決心。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니 그만 포기하고 짐 싸서 나갈 준비나 하세요.","JPN":"ですから、もう諦めて荷物をまとめ出ていく準備でもしてください。","ENG":"So give up and start packing up your stuff.","TWN":"所以妳就乖乖放棄，準備收拾行李離開吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런가요...... 안타깝네요.","JPN":"そうですか……残念です。","ENG":"So that's how you think. What a shame.","TWN":"這樣嗎……太遺憾了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희는 레지나 님이 오기만 손꼽아 기다렸는데...... 정말 친해지고 싶었는데......","JPN":"我々はレジーナ様がいらっしゃる日を\\n首を長くして待っていたのに……本当に親しくなりたかったのに……","ENG":"You have no idea how eagerly we've waited for you to come home. Oh, how we wanted to be friends with you...","TWN":"我們一直期待著蕾佳娜大人的到來……真的很想親近您……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그렇게 불쌍한 표정 지어도 소용없어요!","JPN":"そ、そんなかわいそうな顔をしても無駄ですわ！","ENG":"Th-that sad look on your face won't make me change my mind!","TWN":"就、就算妳露出可憐兮兮的表情也沒用！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"알겠습니다. 레지나 님의 뜻이 그렇다면 더 이상 말씀드리지 않을게요.","JPN":"分かりました。レジーナ様がそこまでおっしゃるならば、もう何も言いません。","ENG":"Okay. If that's your decision, we won't try to persuade you anymore.","TWN":"我們明白了。如果蕾佳娜大人希望如此，那我們也不會再多說什麼了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 대신, 마지막으로 한 번만 학회의 일을 도와 주셨으면 해요.","JPN":"そのかわり、最後に一度だけ学会の仕事を手伝っていただけませんか。","ENG":"Instead, could you please help us with this problem we at the Society have one last time?","TWN":"但相對的，希望您能幫助學會最後一次。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"거절하겠습니다. 전 한 시라도 빨리 이 저택에서 당신네 흔적을 쓸어 내 버리고 싶거든요.","JPN":"お断りします。私は一刻も早くこの邸宅からあなたの痕跡を消したいのです。","ENG":"I refuse. I can't wait to sweep all of your traces off this mansion.","TWN":"容我拒絕，我想儘快把你們的痕跡從這所宅邸徹底抹除掉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"며칠간 말미를 드릴 테니 머물 곳이나 알아 보시죠.","JPN":"数日の猶予をあげますので、行き先を探してください。","ENG":"I'll give you a few days to look for a place to stay.","TWN":"我會給妳幾天的時間，妳就去找個落腳的地方吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......저어, 레지나 님.","JPN":"……あの、レジーナ様。","ENG":"Sorry, Miss Regina.","TWN":"……這，蕾佳娜大人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"죄송하지만 레지나 님께는 그럴 권리가 없으세요.","JPN":"申し訳ありませんが、レジーナ様にはその権利がございません。","ENG":"But you're not really in the position to do that.","TWN":"非常抱歉，但是蕾佳娜大人並沒有權利這麼做。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후훗, 이제야 학회 사람답게 본색을 드러내는군요?","JPN":"ふふっ、ようやく学会の人間らしく本性を現しましたわね？","ENG":"Ha! Now you're revealing your true colors!","TWN":"呵呵，現在才像個學會的人，露出真面目了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜요? 제게 저주라도 내리시게요?","JPN":"なぜです？　私に呪いでもかける気ですの？","ENG":"What, you're going to cast a curse upon me?","TWN":"怎麼？妳要對我下詛咒嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"마음껏 억지를 부려 보세요. 어차피 결과는 바뀌지 않을......","JPN":"好きなだけ足掻いてください。どのみち結果は同じ……","ENG":"Say whatever you want, but you're moving out, no matter wha—","TWN":"妳就盡情地耍賴吧。反正結果不會有任何改……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"전임 학회장님께서 저택을 비롯한 가문의 모든 유산을 저희에게 물려 주겠다고 하셨거든요.","JPN":"先代の学会長が、邸宅をはじめマクレディー家の全遺産を我々に譲るとおっしゃいましたので。","ENG":"The former President willed everything that the family possessed to us.","TWN":"前任學會長說包括這棟宅邸，家族所有的遺產都要留給我們。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......네?","JPN":"……えっ？","ENG":"Huh?","TWN":"……咦？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<b>뭐, 뭐라고요?!</b>","JPN":"<b>な、何ですって！？</b>","ENG":"<b>S-say that again?</b>","TWN":"<b>妳、妳說什麼？！</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};